const body = $input.first().json.body || $input.first().json || {};

const mode = String(body.mode || 'txt2img');
if (mode !== 'txt2img') {
  throw new Error(`Unsupported mode: ${mode}. This workflow currently ships with txt2img; add video/audio by pasting a ComfyUI API prompt template into this node.`);
}

function clampInt(value, fallback, min, max) {
  const n = Number.parseInt(value ?? fallback, 10);
  if (!Number.isFinite(n)) return fallback;
  return Math.min(max, Math.max(min, n));
}

function clampFloat(value, fallback, min, max) {
  const n = Number.parseFloat(value ?? fallback);
  if (!Number.isFinite(n)) return fallback;
  return Math.min(max, Math.max(min, n));
}

const positive = String(body.prompt || body.positive || '').trim();
if (!positive) throw new Error('Missing required field: prompt');

const negative = String(body.negative || 'low quality, blurry, distorted, watermark, text artifacts');
const ckptName = String(body.ckpt_name || 'v1-5-pruned-emaonly-fp16 (2).safetensors');
const width = clampInt(body.width, 512, 256, 1024);
const height = clampInt(body.height, 512, 256, 1024);
const steps = clampInt(body.steps, 22, 1, 60);
const cfg = clampFloat(body.cfg, 7.0, 0, 20);
const sampler = String(body.sampler_name || 'dpmpp_2m');
const scheduler = String(body.scheduler || 'karras');
const seed = body.seed === undefined || body.seed === null || body.seed === ''
  ? Math.floor(Math.random() * 2147483647)
  : clampInt(body.seed, 0, 0, 2147483647);
const batchSize = clampInt(body.batch_size, 1, 1, 1);
const filenamePrefix = String(body.filename_prefix || `n8n/${mode}`);

const prompt = {
  '1': { class_type: 'CheckpointLoaderSimple', inputs: { ckpt_name: ckptName } },
  '2': { class_type: 'CLIPTextEncode', inputs: { text: positive, clip: ['1', 1] } },
  '3': { class_type: 'CLIPTextEncode', inputs: { text: negative, clip: ['1', 1] } },
  '4': { class_type: 'EmptyLatentImage', inputs: { width, height, batch_size: batchSize } },
  '5': {
    class_type: 'KSampler',
    inputs: {
      seed,
      steps,
      cfg,
      sampler_name: sampler,
      scheduler,
      denoise: 1,
      model: ['1', 0],
      positive: ['2', 0],
      negative: ['3', 0],
      latent_image: ['4', 0]
    }
  },
  '6': { class_type: 'VAEDecode', inputs: { samples: ['5', 0], vae: ['1', 2] } },
  '7': { class_type: 'SaveImage', inputs: { images: ['6', 0], filename_prefix: filenamePrefix } }
};

return [{
  json: {
    comfyuiBody: JSON.stringify({ prompt, client_id: 'n8n-comfyui-media-pipeline' }),
    mode,
    seed,
    ckptName,
    width,
    height,
    steps,
    cfg,
    sampler,
    scheduler,
    filenamePrefix
  }
}];

const queued = $input.first().json || {};
const meta = $('Build ComfyUI Prompt').first().json;
const promptId = queued.prompt_id;

return [{ json: {
  status: 'queued',
  prompt_id: promptId,
  queue_number: queued.number,
  node_errors: queued.node_errors || {},
  mode: meta.mode,
  seed: meta.seed,
  ckpt_name: meta.ckptName,
  width: meta.width,
  height: meta.height,
  status_webhook: 'http://localhost:5678/webhook/comfyui-media-status',
  status_body: { prompt_id: promptId },
  comfyui_history_url: `http://localhost:8188/history/${promptId}`
}}];
